  'function' => 
  array (
    'name' => 'text_coordinate_grid',
    'description' => 'A persistent 2D coordinate grid where text tokens/items can be placed at (x,y) positions. Supports place (put a token), get (retrieve at position), scan (list everything in a rectangle), move (relocate a token), neighbors (get adjacent cells), and clear. Uses persistent notes for storage. Pure function but persists state.',
    'parameters' => 
