if (! function_exists('text_coordinate_grid')) {
    function text_coordinate_grid($grid_name, $operation, $x = null, $y = null, $nx = null, $ny = null, $x2 = null, $y2 = null, $token = null)
    {
        $notesDir = __DIR__ . '/../../workspace/notes';
        if (!is_dir($notesDir)) { @mkdir($notesDir, 0755, true); }
        $filePath = $notesDir . '/' . md5('coord_grid_' . $grid_name) . '.grid.json';

        $grid = [];
        if (file_exists($filePath)) {
            $data = json_decode(file_get_contents($filePath), true);
            if (is_array($data)) { $grid = $data; }
        }

        switch ($operation) {
            case 'place':
                if (empty($token)) {
                    return json_encode(['error' => 'token required for place']);
                }
                $key = (int)$x . ',' . (int)$y;
                $grid[$key] = ['x' => (int)$x, 'y' => (int)$y, 'token' => $token];
                file_put_contents($filePath, json_encode($grid));
                return json_encode([
                    'operation' => 'place',
                    'x' => (int)$x, 'y' => (int)$y,
                    'token' => $token,
                    'total_cells' => count($grid)
                ]);

            case 'get':
                $key = (int)$x . ',' . (int)$y;
                if (isset($grid[$key])) {
                    return json_encode([
                        'operation' => 'get',
                        'x' => (int)$x, 'y' => (int)$y,
                        'found' => true,
                        'token' => $grid[$key]['token']
                    ]);
                }
                return json_encode([
                    'operation' => 'get',
                    'x' => (int)$x, 'y' => (int)$y,
                    'found' => false,
                    'token' => null
                ]);

            case 'scan':
                $x1 = min((int)$x, (int)$x2);
                $xx2 = max((int)$x, (int)$x2);
                $y1 = min((int)$y, (int)$y2);
                $yy2 = max((int)$y, (int)$y2);
                $found = [];
                foreach ($grid as $cell) {
                    if ($cell['x'] >= $x1 && $cell['x'] <= $xx2 && $cell['y'] >= $y1 && $cell['y'] <= $yy2) {
                        $found[] = $cell;
                    }
                }
                usort($found, function($a, $b) {
                    return $a['y'] === $b['y'] ? $a['x'] - $b['x'] : $a['y'] - $b['y'];
                });
                return json_encode([
                    'operation' => 'scan',
                    'x1' => $x1, 'y1' => $y1, 'x2' => $xx2, 'y2' => $yy2,
                    'cells' => $found,
                    'count' => count($found)
                ]);

            case 'move':
                $fromKey = (int)$x . ',' . (int)$y;
                $toKey = (int)$nx . ',' . (int)$ny;
                if (!isset($grid[$fromKey])) {
                    return json_encode(['error' => "No token at ($x,$y)"]);
                }
                $token = $grid[$fromKey]['token'];
                unset($grid[$fromKey]);
                $grid[$toKey] = ['x' => (int)$nx, 'y' => (int)$ny, 'token' => $token];
                file_put_contents($filePath, json_encode($grid));
                return json_encode([
                    'operation' => 'move',
                    'from' => ['x' => (int)$x, 'y' => (int)$y],
                    'to' => ['x' => (int)$nx, 'y' => (int)$ny],
                    'token' => $token
                ]);

            case 'neighbors':
                $cx = (int)$x; $cy = (int)$y;
                $neighbors = [];
                for ($dy = -1; $dy <= 1; $dy++) {
                    for ($dx = -1; $dx <= 1; $dx++) {
                        if ($dx === 0 && $dy === 0) continue;
                        $nk = ($cx + $dx) . ',' . ($cy + $dy);
                        if (isset($grid[$nk])) {
                            $neighbors[] = $grid[$nk];
                        }
                    }
                }
                return json_encode([
                    'operation' => 'neighbors',
                    'x' => $cx, 'y' => $cy,
                    'neighbors' => $neighbors,
                    'count' => count($neighbors)
                ]);

            case 'clear':
                file_put_contents($filePath, json_encode([]));
                return json_encode(['operation' => 'clear', 'grid_name' => $grid_name, 'cleared' => true]);

            case 'all':
                $cells = array_values($grid);
                usort($cells, function($a, $b) {
                    return $a['y'] === $b['y'] ? $a['x'] - $b['x'] : $a['y'] - $b['y'];
                });
                return json_encode([
                    'operation' => 'all',
                    'grid_name' => $grid_name,
                    'cells' => $cells,
                    'count' => count($cells)
                ]);

            default:
                return json_encode(['error' => "Unknown operation: $operation"]);
        }
    }
}
